def solve(nums, target):
    left, right = 0, len(nums) - 1
    while left < right:
        total = nums[left] + nums[right]
        if total == target:
            return left, right
        if total < target:
            left += 1
        else:
            right -= 1
    return -1, -1

# Additional checks for pitfalls
def solve_with_checks(nums, target):
    if len(nums) < 2:
        return -1, -1  # Handle no-solution case for less than 2 numbers
    seen = {}
    for i, num in enumerate(nums):
        complement = target - num
        if complement in seen:
            return seen[complement], i
        seen[num] = i
    return -1, -1

# Unit tests for critical behaviors
def test_solve():
    assert solve([1, 2, 3, 4, 5], 5) == (0, 3)
    assert solve([1, 2, 3, 4, 5], 10) == (-1, -1)
    assert solve([1, 2, 3, 4, 5], 6) == (1, 3)
    assert solve([], 5) == (-1, -1)  # No solution case
    assert solve([1], 1) == (-1, -1)  # No solution case

# Adversarial/edge-case tests
def test_edge_cases():
    assert solve([1, 2], 3) == (0, 1)  # Minimum valid input
    assert solve([1, 1, 1, 1], 2) == (0, 1)  # Duplicate numbers
    assert solve([1, 2, 3, 4, 5], 0) == (-1, -1)  # No solution case
    assert solve([5, 5, 5, 5], 10) == (0, 1)  # Same number multiple times

# Run tests
test_solve()
test_edge_cases()
